import React from 'react';
import { FiGrid, FiX } from 'react-icons/fi'
import anime from 'animejs';
import propTypes from 'prop-types';


export default class Menu extends React.Component {

    static propTypes = {

    }

    state = {
        open: false,
        animating: false
    }
    componentDidMount(){
        if(this.props.open){
            this._toggle()
        }
    }

    _toggle = () => {

        const setIconAnimate = (open) => ({
            opacity: [0,1],
            translateY: !open? 0 : [50,0],
            translateY: !open? 0 : [20,0]
        })

        const setWrapperAnimate = (open) => ({
            height: !open ? ['30px','100%'] : ['100%','30px'],
            width: !open ? '100%': '30px',
            top: !open ? 0 : '2vw',
            right: !open ? 0 : '2vw',
            background: !open ? 'linear-gradient(180deg, rgba(13,13,13,0.8) 0%, rgba(33,33,33,0.8) 100%)' : 'rgba(0,0,0,0)'
        })

        if (!this.state.animating) {
            this.setState({ animating: true })
            anime({
                targets: this.icon,
                begin: () => this.setState({open: !this.state.open}),
                ...setIconAnimate(this.state.open),
                easing: 'linear',
                duration: 300,
                complete: () => {
                    if(!this.state.open){
                        if(this.props.onHide) this.props.onHide()
                    }
                }
            })
            anime({
                targets: this.wrapper,
                easing: 'linear',
                duration: 300,
                ...setWrapperAnimate(this.state.open),
                complete: () => { 
                    this.setState({animating: false});
                }
            })
        }
    }

    render() {
        return (
            <div ref={ref => this.wrapper = ref} style={{
                position: 'absolute', top: '2vw', right: '2vw', display: 'flex', alignItems: 'center', flexDirection: 'column', overflow: 'hidden',
                ...this.props.style
            }}>
                <div ref={ref => this.icon = ref} style={{ display: 'flex', justifyContent: 'center', width:'100%' }}>
                    { 
                        this.state.open ? 
                        <FiX color='#ffffff' strokeWidth={1} onClick={() => this._toggle()} size={30} ></FiX>:
                        <FiGrid color='#ffffff' strokeWidth={1} size={30} onClick={() => this._toggle()}></FiGrid>
                    }
                </div>
                <div style={{ display: 'flex', alignItems:'center', justifyContent:'space-around', flexDirection: 'column', width:'100%', height:'100%', }}>
                    { this.state.open && !this.state.animating && this.props.children }
                </div>
            </div>
        )
    }
}