import React, { Component } from 'react';
import propTypes from 'prop-types';
import anime from 'animejs'

const styles = {

    messagesLeft: {
        background: '#ddd',
        padding: 8,
        margin: '2px 8px 2px 0',
        borderRadius: 18,
        color: '#333333'
    },

    messagesRight: {
        borderRadius: 18,
        padding: 8,
        margin: '2px 8px 2px 0',
        alignSelf: 'flex-end',
        background: '#2196f3',
        color: 'white',
    },
    timemark: {
        alignSelf: 'center',
        color: 'dark',
        padding: 10
    },
    bubble: {
        fontSize: '2em',
        position: 'absolute',
        lineHeight: '1rem'
    }
}



class Messenger extends Component {

    static propTypes = {
        data: propTypes.array,
        preloadingTime: propTypes.number,
        loadingAnimation: propTypes.number
    }

    static defaultProps = {
        data: [
        {
            text: 'Hi! This website is still under development. Felix got busy lately.',
            align: 'left'
        },
        {
            text: 'Redirecting you...',
            align:'left'
        },

]
    }

    componentDidMount() {
        this._recursiveAnimate(0)
    }

    _recursiveAnimate = (bubbleId) => {
        if (!this[`bubble-${bubbleId}`]) {
            if (this.props.onComplete) this.props.onComplete()
            return
        }

        var tl = anime.timeline({})
        tl.add({
            targets: this[`bubble-${bubbleId}`],
            duration: 10,
            opacity: 1,
            complete: () => {
                this[`bubble-${bubbleId}`].style.display = 'block';
                console.log(this[`bubble-${bubbleId}`].style.width)
            }
        })
            .add({
                targets: [1, 2, 3].map(val => this[`${bubbleId}-d${val}`]),
                translateY: [-30, 0],
                color: ['#aaaaaa', '#555555', '#aaaaaa', '#888888', '#777777'],
                scale: [1, 0.6, 1],
                delay: this.props.data[bubbleId].align === 'left' ? anime.stagger(50) : 0,
                duration: this.props.data[bubbleId].align === 'left' ? 1200 : 0,
            })
            .add({
                targets: this[`bubble-${bubbleId}`],
                opacity: 1,
                duration: 1,
                complete: () => {
                    this[`dots-${bubbleId}`].style.display = 'none';
                    this[`text-${bubbleId}`].style.display = 'block';
                }
            })
            .add({
                targets: this[`container-${bubbleId}`],
                delay: 0,
                duration: 500,
                width: '100%',
                height: '100%',
                translateY: this.props.data[bubbleId].align === 'left' ? 0 : [100, 0],
                easing: 'easeOutExpo',
                direction: 'reverse',
                complete: () => {
                    this._recursiveAnimate(bubbleId + 1)
                }
            })
    }


    constructor(props) {
        super(props)
        this.conversation = props.data.map((obj, idx) => {
            return (
                <div ref={ref => this[`bubble-${idx}`] = ref} style={{ ...(obj.align === 'left' ? styles.messagesLeft : styles.messagesRight), display: 'none', maxWidth: '80%', position: 'relative', background: 'transparent' }}>
                    <div ref={ref => this[`dots-${idx}`] = ref} style={{ fontSize: '2rem', lineHeight: '0.8em', display: 'flex', flexDirection: 'row', zIndex: 1 }}>
                        <div ref={ref => this[`${idx}-d1`] = ref} >•</div>
                        <div ref={ref => this[`${idx}-d2`] = ref} >•</div>
                        <div ref={ref => this[`${idx}-d3`] = ref} >•</div>
                    </div>
                    <div ref={ref => this[`text-${idx}`] = ref} style={{ display: 'none', zIndex: 1 }}>{obj.text}</div>
                    <div ref={ref => this[`container-${idx}`] = ref} style={{ position: 'absolute', top: 0, left: 0, minWidth: 55, zIndex: -1, minHeight: 40, ...(obj.align === 'left' ? styles.messagesLeft : styles.messagesRight) }}></div>
                </div>
            )
        })
    }

    render() {
        return (
            <div style={{
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'flex-start',
                font: '16px / 1.3 sans - serif',
                height: '100%',
                margin: '0 auto',
                padding: '0 auto',
                overflow: 'auto',
                width: '90%',
                maxWidth: 600,
            }}>

                <div style={styles.timemark}>{new Date().toLocaleString()}</div>
                {this.conversation}
            </div>
        )
    }

}

const data = [
    {
        text: 'I love you.',
        align: 'left'
    },
]

export default class PreloaderScreen extends Component {

    static propTypes = {
        show: propTypes.bool,
        onComplete: propTypes.func,

    }

    static defaultProps = {
        show: true
    }

    state = {
        show: this.props.show
    }

    transition = () => {
        anime({
            targets: this.screen,
            duration: 1000,
            translateY: [0, -window.screen.height * 1.5],
            rotateY: 45,
            width: 0,
            height: 0,
            rotateZ: 45,
            easing: 'easeInCubic'
        })
    }

    componentWillUpdate(props) {
        if (!props.show) this.transition()
    }

    render() {
        return (
            <div style={{ position: 'fixed', width: '100%', height: '100%', top: 0, left: 0, background: 'white' }} ref={ref => this.screen = ref} >
                <Messenger onComplete={this.props.onComplete}></Messenger>
            </div>
        )
    }
}