import React from 'react';



export default class HoverElement extends React.Component {
    onHover = () => {
        Object.keys(this.props.onHoverStyle).map(key => 
            {
                let val = this.props.onHoverStyle[key];
                if(typeof val === 'number'){
                    val = `${val}px`
                }
                this.ref.style[key] = val;
            }
        )
    }

    onLeave = () => {
        Object.keys(this.defaultStyle).map(key => { 
            let val = this.defaultStyle[key];
                if(typeof val === 'number'){
                    val = `${val}px`
                }
            this.ref.style[key] = val
        })
    }

    render() {
        const childElement = React.Children.only(this.props.children);
        this.defaultStyle = childElement.props.style
        return React.cloneElement(
                    childElement,
                    { 
                        ref: el => this.ref = el, 
                        style: {...childElement.props.style, ...this.props.style},
                        onMouseEnter: () => this.onHover(),
                        onMouseLeave: () => this.onLeave(),
                    }
                )
            
    }
}