import React, { Component } from 'react';
import propTypes from 'prop-types';



class Color {
    constructor(color) {
        this.color = color;
        this.opacity = 1;
        this.dAlpha = 0
    }

    _hexToRgba = (hex, opacity) => {
        var shorthandRegex = /^#?([a-f\d])([a-f\d])([a-f\d])$/i;
        hex = hex.replace(shorthandRegex, (m, r, g, b) => r + r + g + g + b + b);
        var result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
        return result ? `rgba(${parseInt(result[1], 16)}, ${parseInt(result[2], 16)}, ${parseInt(result[3], 16)}, ${opacity})` : 'rgba(0,0,0,1)';
    }

    getAlpha = () => {
        return this.dAlpha
    }

    setAlpha = (alpha) => {
        this.dAlpha = alpha
    }

    update = () => {
        this.opacity = Math.min(this.dAlpha + this.opacity, 1)
    }

    setColor = (color) => {
        this.color = color
    }

    getRGBA = () => {
        var color = this.color
        return this._hexToRgba(color, this.opacity);
    }
}


class Particle {

    constructor(args){
        this.props = {
            ctx: args.ctx,
            color: {
                type: 'solid',
                animationSync: args.transition,
                main: args.color,
                glow: args.glowColor ? args.glowColor : false
            },
            shape: {
                radius: 4,
                minRadius: args.fMinRadius,
                maxRadius: args.fMaxRadius,
                startAngle: 0,
                endAngle: Math.PI * 2,
                fill: true
            },
            motion: {
                vel: {
                    x: Math.random() * (Math.random() - 0.5),
                    y: Math.random() * (Math.random() - 0.5),
                },
                rot: {
                    x: 0,
                    y: 0
                },
                location: {
                    x: args.x,
                    y: args.y
                },
                lifeSpan: 3000,
                frontDirection: ['approach', 'away'][Math.floor(Math.random() * 2)],
            },
            animation: {
                time: (args.tLifeTimeMax-args.tLifeTimeMin) * Math.random() + args.tLifeTimeMin,
                interval: 20,
                fadeIn: args.tFadeIn,
                fadeOut: args.tFadeOut,
            }
        }
        this._initial()

    }

    _initial = () => {
        // transition events
        // --smooth transition when particle created and destroyed (fading In and out)
        this.isActive = true
        this.pColor = new Color(this.props.color.main);
        switch (this.props.color.animationSync) {
            case 'fadeIn':
                this.pColor.opacity = 0
                this.pColor.setAlpha(this.props.animation.interval / this.props.animation.fadeIn)
                break

            case 'fadeIn-Out':
                this.pColor.opacity = 0
                this.pColor.setAlpha(this.props.animation.interval / this.props.animation.fadeIn)
                setTimeout(this._fadeOut, this.props.animation.time - this.props.animation.fadeOut)
                break

            case 'fadeOut':
                this.pColor.setAlpha(1)
                setTimeout(this._fadeOut, this.props.animation.time - this.props.animation.fadeOut)
                break

            case 'persisent':
            default:
                this.pColor.setAlpha(0)
                break
        }

        // motion events
        // --the feeling of particle moving in 3 Dimension (closing/away)
        switch (this.props.motion.frontDirection) {
            case 'approach':
            default:
                this.props.shape.radius = this.props.shape.minRadius
                this.props.shape.dScale = (this.props.shape.maxRadius - this.props.shape.minRadius) /
                    (this.props.animation.time / this.props.animation.interval)
                break

            case 'away':
                this.props.shape.radius = this.props.shape.maxRadius
                this.props.shape.dScale = -(this.props.shape.maxRadius - this.props.shape.minRadius) /
                    (this.props.animation.time / this.props.animation.interval)
                break
        }

        setTimeout(() => this.isActive = false, this.props.animation.time)
    }


    draw = () => {
        this.pColor.update()
        this.props.motion.location.x += this.props.motion.vel.x
        this.props.motion.location.y += this.props.motion.vel.y

        // determine size
        this.props.shape.radius = Math.min(
            Math.max(this.props.shape.radius + this.props.shape.dScale, this.props.shape.minRadius),
            this.props.shape.maxRadius)
        this.props.ctx.fillStyle = this.pColor.getRGBA()

        // determine shape
        this.props.ctx.beginPath();
        this.props.ctx.arc(this.props.motion.location.x,
            this.props.motion.location.y,
            this.props.shape.radius,
            0, Math.PI * 2)
        
        //set glowing effect
        if(this.props.color.glow){
            this.props.ctx.shadowBlur = 20;
            this.props.ctx.shadowColor = this.pColor._hexToRgba(this.props.color.glow, this.pColor.opacity);
        }
        
    
        this.props.ctx.fill()
    }

    _fadeOut = () => {
        this.pColor.setAlpha(- this.props.animation.interval / this.props.animation.fadeOut)
    }

}


class ParticleContainer extends Component {

    static propTypes = {
        children: propTypes.node,
        className: propTypes.string,

        //-----------remake--------------
        particle: propTypes.shape({
            color: propTypes.string,
            glowColor: propTypes.oneOf([propTypes.string, propTypes.bool]),
            transition: propTypes.oneOf(['fadeIn', 'fadeOut', 'fadeIn-Out', 'persistent']),
            lifeTimeMax: propTypes.number,
            lifeTimeMin: propTypes.number,
            fadeInDuration: propTypes.number,
            fadeOutDuration: propTypes.number,
            spanNumber: propTypes.number,
            shape: propTypes.oneOf(['circle', 'round']),
            maxSize: propTypes.number,
            minSize: propTypes.number,
        }),
        //events
        loaded: propTypes.func

    }

    static defaultProps = {
        particle: {
            color: '#c62828',
            glowColor: false,
            transition: 'fadeIn-Out',
            lifeTimeMax: 8000,
            lifeTimeMin: 5000,
            fadeInDuration: 1500,
            fadeOutDuration: 1500,
            shape: 'circle',
            maxSize: 6,
            minSize: 1,
            spanNumber: 20,
        },
        loaded: null
    }

    componentDidMount() {
        this._eventStart()
        setInterval(this._eventLoop, 20);
        window.addEventListener('resize', this._windowInitial)
        document.addEventListener('readystatechange', this._documentStateChange)
    }


    componentWillUnmount(){
        window.removeEventListener('resize', this._windowInitial)
        document.removeEventListener('readystatechange', this._documentStateChange)
    }


    _windowInitial = () => {
        this._rect = this._wrapper.getBoundingClientRect()
        this._dpr = window.devicePixelRatio || 1;
        this._canvas.width = this._rect.width * this._dpr
        this._canvas.height = this._rect.height * this._dpr
        this._ctx = this._canvas.getContext('2d');
        this._ctx.scale(this._dpr, this._dpr)
    }

    render() {
        const {
            children,
            className,
        } = this.props
        //preset Style children
        if (children)
        children.props.style.position = 'absolute'

        return (
            <div className={className} style={{
                zIndex:-1,
                position: 'absolute', width: '100%', height: '100%', 
                top:0,
                background: this.props.background,
                backgroundSize: 'cover',
                backgroundPosition: 'center center',
                backgroundRepeat: 'no-repeat',
                backgroundAttachment:'fixed',
                ...this.props.style
            }}
            ref={this._wrapperRef}>
                <canvas ref={this._canvasRef} style={{
                    zIndex:0,
                    position: 'absolute', background: 'rgba(10,0,10,0.7)', opacity: 0.87, width: '100%', height: '100%',
                    ...this.props.canvasStyle
                }} />
                {children}
            </div>
        )
    }

    _documentStateChange = (e) => {
        if(document.readyState === 'complete'){
            return this.props.loaded ? this.props.loaded(e) : null
        }
    }
    /* Private methods */
    _eventLoop = () => {
        this._updateParticles()
    }

    _eventStart = () => {
        /* logic drawing */

        this._windowInitial()
        this._maxParticle = this.props.particle.spanNumber
        this._particles = []
        //common particle's props (except theirs location x, y --> will be randomized and set later)
        this._particleProps = {
            ctx: this._ctx,
            color: this.props.particle.color,
            glowColor: this.props.particle.glowColor,
            transition: this.props.particle.transition,
            fMinRadius: this.props.particle.minSize,
            fMaxRadius: this.props.particle.maxSize,
            tLifeTimeMax: this.props.particle.lifeTimeMax,
            tLifeTimeMin: this.props.particle.lifeTimeMin,
            tFadeIn: this.props.particle.fadeInDuration,
            tFadeOut: this.props.particle.fadeOutDuration,
        }
        this._addParticles()

    }


    _addParticle = (obj) => {
        this._particles.push(obj)
    }

    _addParticles = () => {
        for (var i = 0; i < this._maxParticle; i++) {
            this._addParticle(
                new Particle(
                    {
                        ...this._particleProps,
                        x: Math.random() * this._rect.width,
                        y: Math.random() * this._rect.height,
                    }
                )
            )
        }
    }

    _updateParticles = () => {
        this._ctx.clearRect(0, 0, this._canvas.width, this._canvas.height)
        for (var i = 0; i < this._particles.length; i++) {
            if (this._particles[i].isActive)
                this._particles[i].draw()
            else {
                this._particles[i] = new Particle(
                    {
                        ...this._particleProps,
                        x: Math.random() * this._rect.width,
                        y: Math.random() * this._rect.height,
                    }
                )
            }
        }
    }

    _wrapperRef = (ref) => { this._wrapper = ref }
    _canvasRef = (ref) => { this._canvas = ref }
}

export default ParticleContainer;
